const rows = $input.all().map(i => i.json);

const observerMap = {};

for (const r of rows) {

  const emails = (r.observer_emails || '').split(',');
  const firstNames = (r.observer_first_names || '').split(',');
  const lastNames = (r.observer_last_names || '').split(',');

  for (let i = 0; i < emails.length; i++) {

    const email = emails[i]?.trim();
    if (!email) continue;

    if (!observerMap[email]) {
      observerMap[email] = {
        observer_email: email,
        observer_name: `${firstNames[i] || ''} ${lastNames[i] || ''}`.trim(),
        tasks: []
      };
    }

    observerMap[email].tasks.push({
      ...r, // keep full task info
      observer_email: email,
      observer_first_name: firstNames[i]?.trim(),
      observer_last_name: lastNames[i]?.trim()
    });
  }
}

return Object.values(observerMap);

const rows = $input.all().map(i => i.json);

const ownerMap = {};

for (const r of rows) {

  const email = r.responsible_person_email;
  if (!email) continue;

  const name = `${r.responsible_person_firstname || ''} ${r.responsible_person_lastname || ''}`.trim();

  if (!ownerMap[email]) {
    ownerMap[email] = {
      task_owner_email: email,
      task_owner_name: name,
      tasks: []
    };
  }

  ownerMap[email].tasks.push({
    subtask_id: r.subtask_id,
    subtask_title: r.subtask_title,
    subtask_created_on: r.subtask_created_on,
    subtask_end_on: r.subtask_end_on,
    subtask_status: r.subtask_status,
    overdue_days: r.overdue_days,

    priority: r.subtask_priority || 'N/A',

    parent_task_id: r.parent_task_id || 'N/A',
    parent_task_title: r.parent_task_title || 'N/A',

    project_title: r.project_title || 'N/A',

    milestone_title: r.milestone_title ?? 'N/A'
  });
}

// convert + add total count per owner
return Object.values(ownerMap).map(owner => ({
  json: {
    ...owner,
    total_overdue_subtasks: owner.tasks.length
  }
}));

